{
  "name": "Senior Health Information and Insurance Education (SHIINE)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Medicare beneficiaries, those approaching Medicare, and their caregivers[2][4]",
    "asset_limits": "No asset limits or tests apply[2][4]",
    "other_requirements": ["Must be a Medicare beneficiary in South Dakota, approaching Medicare eligibility, or a caregiver of someone on Medicare[2][4]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free personalized health insurance counseling and education on Medicare Parts A/B, Part D, Medicare Advantage, Medigap, long-term care insurance, Medicare Savings Programs (QMB/SLMB/QI), prescription assistance, Medicaid, and other programs; application assistance for low-income programs like LIS; fraud prevention via SMP; group education events, one-on-one enrollment help (especially during Part D open enrollment), printed materials, and referrals[1][2][3][5]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Toll-free (800) 536-8197[3][6]", "Website: https://www.shiine.net[3]", "Email: caitlin.christensen@state.sd.us or region-specific like western_region@shiine.net[3][4]", "Call to schedule in-person or phone appointment; leave voicemail if needed[4]"],
    "processing_time": "No formal processing; services provided via appointment scheduling, typically immediate upon contact[4]",
    "waitlist": null,
    "forms": ["No specific forms required; counselors assist with applications for related programs like LIS during sessions[1][4]"],
    "documents": ["None required[4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to all South Dakota Medicare beneficiaries[2][4]",
    "regional_variations": "Delivered through regional coordinators and volunteers who recruit/train locally, host events per county (minimum 1 Medicare education event per county, weekly Part D events during enrollment, 2 outreach events per Native American reservation per region/year); may have region-specific contacts/providers but uniform services[1][4]",
    "offices_or_providers": ["Administered by SD Department of Social Services, 700 Governors Drive, Pierre SD 57501-2291; regional coordinators (e.g., Western/Central SD contact: western_region@shiine.net)[1][3][4]"]
  },
  "official_source": "https://dhs.sd.gov/en/ltss/shiine",
  "gotchas": ["Not a direct financial or healthcare service provider—offers education, counseling, and application help only, not payment for care or medical services; staff/volunteers cannot have active insurance licenses[1][5]", "Requires contacting to schedule; no walk-in specified, voicemail if no answer[4]", "Focuses on Medicare-related issues; for LTSS/Medicaid, provides info/referrals but separate processes apply with income/asset limits[6]"],
  "data_shape_notes": "no income/asset test; volunteer-based statewide counseling network with required regional events and outreach; services are educational/advocacy-focused, not benefits-paying"
}

{
  "name": "Meals on Wheels",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict income limits specified for the core Meals on Wheels program in South Dakota; eligibility prioritizes need over earnings. Some programs serve low-income seniors first, and Medicaid/SSI recipients may qualify. Federal poverty guidelines may apply in certain cases, but no specific dollar amounts or household size tables provided for this program. Separate programs like South Dakota Medicaid have 2022 limits of $10,092 annual income/$2,000 assets for singles and $15,132/$3,000 for married couples, but these are not directly for Meals on Wheels.",
    "asset_limits": "No asset limits mentioned for Meals on Wheels; not a primary requirement.",
    "other_requirements": ["Homebound and unable to cook or shop independently", "Spouse or dependent adult living with eligible senior (60+) may qualify", "Under 60: Contact Dakota at Home for possible eligibility if disabled"]
  },
  "benefits": {
    "type": "service",
    "value": "One hot nutritious home-delivered meal per day, Monday-Friday (5 days/week); congregate dining available at sites. Suggested donation $5.25-$15/meal (no one denied for inability to pay); private pay options $9.49-$15/meal or $300/month.",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Call local providers (e.g., Active Generations: (605) 333-3305 or 1-833-663-9673 for Dakota at Home)", "Enroll online via Dakota at Home Referral Form or provider sites (e.g., Meals on Wheels Western South Dakota brochure request)", "Phone registration with providers like Meals on Wheels Sioux Falls or Active Generations"],
    "processing_time": "Not specified",
    "waitlist": "Limited meals available; priority for those in greatest need, but no one 60+ denied for inability to contribute[3]",
    "forms": ["Dakota at Home Referral Form", "Provider-specific application forms (paper or online)"],
    "documents": ["Proof of age (e.g., driver's license, birth certificate)", "Doctor’s note or medical records if disabled/under 60", "Proof of income if requested (not always required)", "Call providers for specifics"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Varies by region; not uniform across South Dakota",
    "regional_variations": "Western South Dakota: Meals on Wheels Western South Dakota serves 64 communities, congregate or home delivery[3]. Sioux Falls: Specific site on W. 46th Street, homebound 60+[2]. Active Generations area: Deliveries Mon-Fri 10:45am-12:30pm, suggested $5.25/meal[7]. Under 60 referrals to Dakota at Home statewide[2][7]. Different providers handle regions.",
    "offices_or_providers": ["Meals on Wheels Western South Dakota", "Meals on Wheels Sioux Falls (W. 46th Street)", "Active Generations (contact Samantha Locke at slocke@activegen.org or (605) 333-3305)", "Dakota at Home (1-833-663-9673)", "The Center (administers some programs)"]
  },
  "official_source": "No single statewide .gov site; administered locally via Older Americans Act through providers like dakotaathome.sd.gov and regional non-profits.",
  "gotchas": ["Not statewide—must contact local provider for your area", "Limited meals; priority by need, potential waitlist despite 'no denial for inability to pay'[3]", "Under 60 requires Dakota at Home referral, not direct Meals on Wheels[2][7]", "Suggested donations/contributory basis, private pay for extras", "Homebound status key—not just age", "Varies by provider; some offer congregate dining vs. only delivery"],
  "data_shape_notes": "Decentralized by region with local providers; no uniform income test or statewide application; Older Americans Act-funded with priority for homebound 60+; referrals for younger via Dakota at Home"
}

{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Annual family income no more than 125% of the Federal Poverty Level (FPL). Exact dollar amounts vary annually by household size and are not specified in current sources; families must check current FPL guidelines via HHS or program contacts for precise figures (e.g., for 2026, consult official tables).[1][2][3]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": [
      "Resident of South Dakota",
      "Unemployed",
      "Eligible to work in the United States"
    ]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time community service work (average 20 hours per week) at non-profit/public organizations (e.g., schools, hospitals, senior centers, day care); paid the highest of federal, state, or local minimum wage; training and counseling to develop skills; free annual physical exams; assistance toward unsubsidized full- or part-time employment; social/physical activities supporting independence.[1][2][3][4]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Electronic: SCSEP application form (Adobe PDF) via DLR website",
      "In-person: Any South Dakota Department of Labor and Regulation (DLR) local office",
      "Phone: Contact DLR workforce experts (specific numbers via coverage map on DLR site)",
      "Mail: Submit completed form to DLR offices (addresses via site)"
    ],
    "processing_time": "Not specified in sources.",
    "waitlist": "Not mentioned; may vary by region due to limited coverage areas.",
    "forms": [
      "SCSEP application form (Adobe PDF)"
    ],
    "documents": [
      "Proof of age, residency, income (to verify ≤125% FPL), unemployment status, work eligibility (e.g., ID, SSN); specifics not detailed—prepare standard verification documents."
    ]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Limited to three areas: West River, East River, and Central (see coverage map on DLR site for counties and contacts).",
    "regional_variations": "Offered only in specified regions with different contact points; potential variations in wait times, host agencies, or availability by area.",
    "offices_or_providers": [
      "South Dakota Department of Labor and Regulation (DLR) local offices in West River, East River, Central areas (map with contacts at dlr.sd.gov/workforce_services/individuals/scsep/participants.aspx)"
    ]
  },
  "official_source": "https://dlr.sd.gov/workforce_services/individuals/scsep/participants.aspx",
  "gotchas": [
    "Not available statewide—only in West River, East River, Central regions; check map first.",
    "Priority enrollment for veterans/qualified spouses, then those 65+, disabled, rural residents, homeless/at-risk, low literacy/English proficiency, low employment prospects, or prior American Job Center users.[3]",
    "Income test strictly at 125% FPL; participants must be unemployed at enrollment.",
    "Temporary training positions (not permanent jobs); goal is transition to unsubsidized work.",
    "No specific dollar amounts for wages beyond minimum wage tie; actual pay depends on local minimum."
  ],
  "data_shape_notes": "Regionally restricted to 3 areas (not statewide); priority tiers affect access; income at fixed 125% FPL (varies by household size via annual FPL tables); no asset test."
}

{
  "name": "Long-Term Care Ombudsman",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available without regard to income.",
    "asset_limits": "No asset limits; no financial eligibility requirements.",
    "other_requirements": ["Resident of a long-term care facility in South Dakota (nursing home, assisted living, or community living home), or family/friend advocating for such a resident or someone attempting to enter.", "Complaint or issue must impact the health, safety, welfare, or rights of a resident."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy for residents' rights; complaint resolution; information and referral assistance; education on residents' rights; review of medical records; assistance with guardianship, medical/treatment issues, facility problems (e.g., staffing shortages); systemic issue identification and resolution.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 605-773-3656 (to discuss or report issue)", "Email: LTCO@state.sd.us (include 'Volunteer' in subject if interested in volunteering, but for services contact for complaints)", "Website: https://dhs.sd.gov/ltss/ombudsman-program (for information)", "In-person: Local ombudsman offices via Division of Adult Services and Aging"],
    "processing_time": "Not specified; complaint handling is responsive but no formal timeline given.",
    "waitlist": null,
    "forms": ["None required"],
    "documents": ["None required"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents (or prospective residents) of long-term care facilities statewide.",
    "regional_variations": "Local Long Term Care Ombudsmen (LLTCos) handle regional areas, with state oversight; extensive travel by ombudsmen indicates coverage across South Dakota but potential differences in local response times or staffing.",
    "offices_or_providers": ["Administered by South Dakota Department of Human Services, Division of Adult Services and Aging; local ombudsmen in regions; Pierre office at Highway 34"]
  },
  "official_source": "https://dhs.sd.gov/ltss/ombudsman-program",
  "gotchas": ["Not a Medicaid or financial assistance program—purely advocacy, not direct care (e.g., no helping with walking or wheelchairs); complaints must directly impact long-term care residents (not general issues); does not handle eligibility for placement or public benefits; family/relatives can access on behalf of resident but must focus on resident rights; not for licensing/certification disputes directly."],
  "data_shape_notes": "no income test; open to any long-term care resident statewide without financial barriers; advocacy-only, not service provision or funding; complaint-driven access"
}
